__device__ __forceinline__ T gelu_forward(T x) {
    const T sqrt_2_over_pi = 0.7978845608028654;
    const T coeff = 0.044715;
    T x_cube = x * x * x;
    T inner = sqrt_2_over_pi * (x + coeff * x_cube);
