        T mean = running_mean[col];
        T var = running_var[col];
        T inv_std = rsqrtf(var + eps);
        T normalized = (acc - mean) * inv_std;

        // Scale and shift
        T scaled = normalized * weight_bn[col] + bias_bn[col];

        // GELU activation
        output[row * N + col] = gelu_forward(scaled);
    }
